const config = $('WALIDACJA - Dane i Konfiguracja').item.json;
const taskResp = $input.first().json;

if (!taskResp.id) {
  throw new Error('ClickUp nie zwrocil ID taska. Odpowiedz: ' + JSON.stringify(taskResp));
}

return [{
  json: {
    ...config,
    taskId: taskResp.id,
    taskUrl: taskResp.url,
    taskName: taskResp.name
  }
}];

